import{_ as i,c as e,o as a,aP as r}from"./chunks/framework.CcVWUnOI.js";const m=JSON.parse('{"title":"Three.js","description":"","frontmatter":{},"headers":[],"relativePath":"frontEnd/gis/three/index.md","filePath":"frontEnd/gis/three/index.md","lastUpdated":1773316683000}'),t={name:"frontEnd/gis/three/index.md"};function u(o,l,s,d,n,c){return a(),e("div",null,l[0]||(l[0]=[r('<h1 id="three-js" tabindex="-1">Three.js <a class="header-anchor" href="#three-js" aria-label="Permalink to &quot;Three.js&quot;">​</a></h1><h2 id="three-js加载大模型大数据量优化方案" tabindex="-1">three.js加载大模型大数据量优化方案 <a class="header-anchor" href="#three-js加载大模型大数据量优化方案" aria-label="Permalink to &quot;three.js加载大模型大数据量优化方案&quot;">​</a></h2><ul><li>模型本身优化（最有效） <ul><li>减面（Decimation） <ul><li>Blender / 3ds Max 减面</li><li>保留轮廓，删掉看不见的面</li></ul></li><li>合并几何体（Merge Geometry） <ul><li>相同材质的物体合并成一个 Mesh</li><li>减少 Draw Call</li></ul></li><li>LOD（细节层次） <ul><li>远：低模</li><li>近：高模</li><li>Three.js 自带 THREE.LOD</li></ul></li><li>纹理压缩 &amp; 尺寸 <ul><li>贴图最大 1024×1024 / 2048×2048 足够</li><li>使用 basis / ktx2 压缩纹理</li><li>尽量用 PowerOfTwo 尺寸（256/512/1024）</li></ul></li></ul></li><li>加载与解析优化 <ul><li>使用 glTF /glb <ul><li>最轻量、解析最快的格式</li><li>优先 draco 压缩</li></ul></li><li>Draco 几何压缩 <ul><li>模型体积可缩小 60%~90%</li><li>使用 DRACOLoader</li></ul></li><li>流式加载 / 分块加载 <ul><li>不要一次性加载整个模型</li><li>模型分块，相机靠近再加载</li></ul></li><li>WebWorker 解析 <ul><li>用 GLTFPlugin 或自己拆 Worker</li><li>不阻塞主线程</li></ul></li></ul></li><li>渲染性能优化 <ul><li>InstancedMesh（大量重复物体） <ul><li>树、建筑、零件 → 一个 Draw Call 搞定</li></ul></li><li>Frustum Culling（视锥体裁剪） <ul><li>相机看不见的自动不渲染</li><li>合理设置 <code>mesh.frustumCulled = true</code></li></ul></li><li>Occlusion Culling（遮挡剔除） <ul><li>被挡住的物体不渲染</li><li>可用插件：<code>Three-Mesh-Occlusion</code></li></ul></li><li>关闭阴影 / 简化阴影 <ul><li>阴影非常耗性能</li><li>小阴影贴图尺寸 512/1024</li><li>只给关键物体开阴影</li></ul></li><li>Material 优化 <ul><li>少用 MeshStandardMaterial</li><li>能用 MeshLambert / MeshPhong 就不用 PBR</li><li>关闭不必要的光照</li></ul></li></ul></li><li>内存与控制 <ul><li>及时 dispose <ul><li><code>geometry.dispose()</code></li><li><code>material.dispose()</code></li><li><code>texture.dispose()</code></li></ul></li><li>控制场景物体数量 <ul><li>远处物体直接<code>visible=false</code></li></ul></li><li>降低像素比（pixelRatio） <ul><li><code>renderer.setPixelRatio(Math.min(window.devicePixelRatio, 1.5 或 1))</code></li><li>移动端效果巨大</li></ul></li></ul></li><li>相机与渲染策略 <ul><li>近裁切面别太小 <ul><li>camera.near = 0.1 改成 0.5/1</li><li>提升深度精度，减少闪烁 &amp; GPU 压力</li></ul></li><li>动态限制 FPS <ul><li>inactive 页面降 FPS</li><li>用 setAnimationLoop 自己控制</li></ul></li></ul></li></ul>',3)]))}const _=i(t,[["render",u]]);export{m as __pageData,_ as default};
